<template><div class="panel"><div class="section-head"><div><h2>能力路由</h2><p>候选模型按顺序执行故障切换。</p></div><el-button v-if="auth.hasPermission('model:route:create')" type="primary" @click="open()">新增路由</el-button></div><el-table :data="rows"><el-table-column prop="featureCode" label="功能编码"/><el-table-column prop="name" label="名称"/><el-table-column label="候选模型"><template #default="s">{{modelNames(s.row.candidateModelIds)}}</template></el-table-column><el-table-column label="思考模式"><template #default="s">{{s.row.enableThinking?'启用':'关闭'}}</template></el-table-column><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?'编辑路由':'新增路由'"><el-form label-width="100px"><el-form-item label="功能编码"><el-input v-model="form.featureCode" placeholder="例如 chat"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="候选模型"><el-select v-model="form.candidateModelIds" multiple><el-option v-for="item in models" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item label="思考模式"><el-switch v-model="form.enableThinking"/></el-form-item><el-form-item label="启用"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import http from'../api/http';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),rows=ref([]),models=ref([]),visible=ref(false),form=reactive({id:null,featureCode:'',name:'',candidateModelIds:[],enableThinking:false,enabled:true});async function load(){[rows.value,models.value]=await Promise.all([http.get('/models/routes').then(r=>r.data),http.get('/models').then(r=>r.data)])}/** 打开路由窗口。 */function open(row){Object.assign(form,row?{...row,candidateModelIds:[...row.candidateModelIds]}:{id:null,featureCode:'',name:'',candidateModelIds:[],enableThinking:false,enabled:true});visible.value=true}/** 保存能力路由。 */async function save(){form.id?await http.put(`/models/routes/${form.id}`,form):await http.post('/models/routes',form);visible.value=false;await load();ElMessage.success('保存成功')}/** 删除能力路由。 */async function remove(row){await ElMessageBox.confirm(`确认删除路由「${row.name}」？`);await http.delete(`/models/routes/${row.id}`);await load()}function modelNames(ids){return(ids||[]).map(id=>models.value.find(item=>item.id===id)?.name||id).join(' → ')}onMounted(load)</script>
